const translations={id:{today:"Hari Ini",upcoming:"Libur Yang Akan Datang",suggestions:"Saran Cuti",noHolidayToday:"Bukan Hari Libur",noUpcomingHoliday:"Tidak Ada Libur Mendatang",noNearbySuggestions:"Tidak ada saran cuti untuk waktu dekat",days:"Hari",leaveDays:"hari cuti",leaveDaysShort:"cuti",hours:"Jam",minutes:"Menit",seconds:"Detik",loading:"Memuat...",footer:"Dibuat dengan ☕ oleh"},en:{today:"Today",upcoming:"Upcoming Holiday",suggestions:"Leave Suggestions",noHolidayToday:"Not a Holiday",noUpcomingHoliday:"No Upcoming Holiday",noNearbySuggestions:"No nearby leave suggestions",days:"Days",leaveDays:"leave days",leaveDaysShort:"leave",hours:"Hours",minutes:"Minutes",seconds:"Seconds",loading:"Loading...",footer:"Made with ☕ by"}};function t(t){const e=localStorage.getItem("lang")||"id";return translations[e][t]||t}function updateTranslations(){const e=document.getElementById("todayLabel"),n=document.getElementById("upcomingLabel"),o=document.getElementById("labelDays"),a=document.getElementById("labelHours"),s=document.getElementById("labelMinutes"),i=document.getElementById("labelSeconds"),d=document.getElementById("suggestionsLabel"),u=document.getElementById("langText"),g=document.getElementById("footerText");if(e&&(e.textContent=t("today")),n&&(n.textContent=t("upcoming")),o&&(o.textContent=t("days")),a&&(a.textContent=t("hours")),s&&(s.textContent=t("minutes")),i&&(i.textContent=t("seconds")),d&&(d.textContent=t("suggestions")),u){const t=localStorage.getItem("lang")||"id";u.textContent="en"===t?"ID":"EN"}g&&(g.textContent=t("footer"))}